import './App.css';
import { BrowserRouter, Routes, Route } from "react-router-dom";
import Nav from "./components/Nav";
import UploadPage from "./pages/UploadPage";

function App() {
  return (
    <BrowserRouter>
      <Nav />
      <Routes>
        <Route path="/pages/UploadPage.js" element={<UploadPage />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
